mapper.select:
/* checkSelectionStart */
SELECT
    COUNT(1)
FROM
    ${apiCommon.schema}.WTAKIT
WHERE
    TASKOKY = #{data.taskoky}

    	AND TASKSTS = #{data.tasksts}

/* isSameLocAndLayerApi */
SELECT
	STOCKKY, SKUMKEY
FROM
	${apiCommon.schema}.WSTKKY
WHERE
	AREAKEY = #{data.toareky}
	AND LOCAKEY = #{data.tolocky}
	AND LOLAYER = #{data.tolayer}

/* getFromLocStock */
SELECT
    FRAREKY as AREAKEY, FRLOCKY as LOCAKEY
FROM
    ${apiCommon.schema}.WTAKIT
WHERE
    TASKOKY = #{data.taskoky}
    AND SKUMKEY = #{data.skumkey}

mapper.update:
/* updateApiStockLayerSort */
UPDATE ${apiCommon.schema}.WSTKKY
SET LOLAYER = #{data.lolayer},
	LMODATE = date_format(now(), '%Y%m%d'),
	LMOTIME = date_format(now(), '%H%i%s'),
	LMOUSER = #{apiCommon.useract},
	UPDTCHK = UPDTCHK + 1
WHERE
	WAREKEY = #{data.warekey}
	AND STOCKKY = #{data.stockky}
